# Category: edge_computing_security

import requests

def lambda_handler(event, context):
    request = event['Records'][0]['cf']['request']
    
    # CloudFront converts header names to lowercase for the event object
    enrich_url_header = request['headers'].get('x-enrich-url')

    if enrich_url_header and enrich_url_header[0]['value']:
        enrich_url = enrich_url_header[0]['value']
        
        try:
            # Make an HTTP GET request to the specified URL
            # Use a short timeout to prevent long delays in Lambda@Edge execution
            response = requests.get(enrich_url, timeout=1.0) 
            response.raise_for_status() # Raise an HTTPError for bad responses (4xx or 5xx)
            
            # Get the content from the response
            # Assuming the context data is text and will be passed as a string header
            context_data = response.text 
            
            # Add the fetched context data as a new header to the request
            # CloudFront expects headers as a list of dictionaries with 'key' and 'value'
            request['headers']['x-context-data'] = [{'key': 'X-Context-Data', 'value': context_data}]
            
        except requests.exceptions.RequestException as e:
            # Log the error for debugging (will appear in CloudWatch Logs)
            # If fetching fails, the request proceeds without the enrichment header
            print(f"Error fetching enrichment data from {enrich_url}: {e}")
        except Exception as e:
            # Catch any other unexpected errors
            print(f"An unexpected error occurred during enrichment: {e}")

    return request